	checkQueryResult(t, db.Query("PRAGMA automatic_index=OFF;\n  SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1;"), "1 0.12 real 2 0.1201 real")
	checkQueryResult(t, db.Query("SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1rj;"), "1 0.12 real 2 0.1201 real")
	checkExecOK(t, db.Exec("CREATE TABLE map_integer (id INT, name);\n  INSERT INTO map_integer VALUES(1,'a');\n  CREATE TABLE map_text (id TEXT, name);\n  INSERT INTO map_text VALUES('4','e');\n  CREATE TABLE data (id TEXT, name);\n  INSERT INTO data VALUES(1,'abc');\n  INSERT INTO data VALUES('4','xyz');\n  CREATE VIEW idmap as\n      SELECT * FROM map_integer\n      UNION SELECT * FROM map_text;\n  CREATE TABLE mzed AS SELECT * FROM idmap;"))
	checkQueryResult(t, db.Query("PRAGMA automatic_index=ON;\n  SELECT * FROM data JOIN idmap USING(id);"), "4 xyz e")
	checkQueryResult(t, db.Query("SELECT * FROM data JOIN mzed USING(id);"), "4 xyz e")
