	checkQueryResult(t, db.Query("SELECT word FROM x3 WHERE ruleset=1 AND word MATCH 'a' ORDER BY distance DESC;"), "t u v a")
	checkQueryResult(t, db.Query("SELECT word FROM x3 WHERE ruleset=1 AND word MATCH 'a' ORDER BY word ASC;"), "a t u v")
	checkQueryResult(t, db.Query("SELECT word FROM x3 WHERE ruleset=1 AND word MATCH 'a' ORDER BY word DESC;"), "v u t a")
