// Auto-generated from queryonly.test
func TestSQLite_queryonly(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	checkExecOK(t, db.Exec("CREATE TABLE t1(a);\n  INSERT INTO t1 VALUES(123),(456);\n  SELECT a FROM t1 ORDER BY a;"))
	checkQueryResult(t, db.Query("PRAGMA query_only;"), "0")
	checkQueryResult(t, db.Query("PRAGMA query_only=ON;\n  PRAGMA query_only;"), "1")
	checkQueryResult(t, db.Query("SELECT a FROM t1 ORDER BY a;"), "123 456")
	checkQueryResult(t, db.Query("PRAGMA query_only=OFF;\n  PRAGMA query_only;"), "0")
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES(789);\n  SELECT a FROM t1 ORDER BY a;"))
	checkExecOK(t, db.Exec("UPDATE t1 SET a=a+1;\n  SELECT a FROM t1 ORDER BY a;"))
	for _, d := range dbs { d.Close() }
}
