// Auto-generated from quota.test
func TestSQLite_quota(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	_ = db.Query("PRAGMA page_size=1024;\n    PRAGMA auto_vacuum=OFF;\n    PRAGMA journal_mode=DELETE;")
	checkExecOK(t, db.Exec("CREATE TABLE t1(a, b);\n    INSERT INTO t1 VALUES(1, randomblob(1100));\n    INSERT INTO t1 VALUES(2, randomblob(1100));"))
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES(3, randomblob(1100))"))
	_ = db.Query("PRAGMA page_size = 1024;\n    PRAGMA journal_mode = delete;\n    PRAGMA auto_vacuum = off;\n    CREATE TABLE t1(a PRIMARY KEY, b);\n    INSERT INTO t1 VALUES(1, 'one');")
	checkExecOK(t, db.Exec("CREATE TABLE t2(a, b)"))
	checkExecOK(t, db.Exec("CREATE TABLE t3(a, b)"))
	_ = db.Query("PRAGMA page_size = 1024;\n      PRAGMA journal_mode = delete;\n      PRAGMA auto_vacuum = off;\n      CREATE TABLE t1(a, b);")
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES('x', 'y')"))
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES('v', 'w')"))
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES('t', 'u')"))
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES('r', 's')"))
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES(randomblob(500), randomblob(500))"))
	checkExecOK(t, db.Exec("CREATE TABLE t2(x); INSERT INTO t2 VALUES('tab-t2');"))
	checkExecOK(t, db.Exec("CREATE TABLE t1(x);\n     INSERT INTO t1 VALUES(randomblob(5000));"))
	db.Close()
	db = setupDB(t)
	dbs = append(dbs, db)
	_ = db.Query("SELECT count(*) FROM sqlite_master")
	checkExecOK(t, db.Exec("DELETE FROM t1"))
	for _, d := range dbs { d.Close() }
}
