func TestSQLite_quote(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	_ = db.Query("SELECT '@abc'.'!pqr', '@abc'.'#xyz'+5 FROM '@abc'")
	checkExecOK(t, db.Exec("UPDATE '@abc' SET '#xyz'=11"))
	checkExecOK(t, db.Exec("DROP TABLE '@abc'"))
	db.Close()
	db = setupDB(t)
	dbs = append(dbs, db)
	checkExecOK(t, db.Exec("CREATE TABLE t1(x, y, z);"))
	_ = db.Query("PRAGMA writable_schema = 1;\n  CREATE TABLE xyz(a, b, c CHECK (c!=\"null\") );\n  CREATE INDEX i2 ON t1(x, y, z||\"abc\");\n  CREATE INDEX i3 ON t1(\"w\"||\"\");\n  CREATE INDEX i4 ON t1(x) WHERE z=\"w\";")
	db.Close()
	db = setupDB(t)
	dbs = append(dbs, db)
	checkExecOK(t, db.Exec("INSERT INTO xyz VALUES(1, 2, 3);"))
	if err := db.Exec("INSERT INTO xyz VALUES(1, 2, 'null');").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	checkExecOK(t, db.Exec("INSERT INTO t1 VALUES(1, 2, 3);\n  INSERT INTO t1 VALUES(4, 5, 'w');\n  SELECT * FROM t1 WHERE z='w';"))
	checkQueryResult(t, db.Query("SELECT sql FROM sqlite_master;"), "{CREATE TABLE t1(x, y, z)}\n  {CREATE TABLE xyz(a, b, c CHECK (c!=\"null\") )}\n  {CREATE INDEX i2 ON t1(x, y, z||\"abc\")}\n  {CREATE INDEX i3 ON t1(\"w\"||\"\")}\n  {CREATE INDEX i4 ON t1(x) WHERE z=\"w\"}")
	if err := db.Exec("CREATE TABLE t1(a,b);\n      CREATE INDEX x1 on t1(\"b\");\n      ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	if err := db.Exec("DROP TABLE t1;\n    CREATE TABLE t1(a,\"b\");\n    CREATE INDEX x1 on t1(\"b\");\n    ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	if err := db.Exec("DROP TABLE t1;\n    CREATE TABLE t1(a,'b');\n    CREATE INDEX x1 on t1(\"b\");\n    ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	if err := db.Exec("DROP TABLE t1;\n    CREATE TABLE t1(a,\"b\");\n    CREATE INDEX x1 on t1('b');\n    ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	if err := db.Exec("DROP TABLE t1;\n    CREATE TABLE t1(a, b, c);\n    CREATE INDEX x1 ON t1(\"a\"||\"b\");\n    INSERT INTO t1 VALUES(1,2,3),(1,4,5);\n    ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	if err := db.Exec("DROP TABLE t1;\n    CREATE TABLE t1(a, b, c);\n    CREATE INDEX x1 ON t1(\"a\"||\"x\");\n    INSERT INTO t1 VALUES(1,2,3),(1,4,5);\n    ALTER TABLE t1 DROP COLUMN b;").Error; err == nil {
		t.Errorf("expected error but got none")
	}
	for _, d := range dbs { d.Close() }
}
